const { chromium } = require\('playwright'\);
async function sleep\(ms\) { return new Promise\(r => setTimeout\(r, ms\)\); }
\(async \(\) => {
  const browser = await chromium.launch\({ headless: true }\);
  const ctx = await browser.newContext\({ viewport: { width: 1280, height: 800 } }\);
  const page = await ctx.newPage\(\);
  const logs = [];
  page.on\('console', msg => logs.push\({ type: msg.type\(\), text: msg.text\(\) }\)\);

  // Login
  await page.goto\('http://localhost:5173/login'\);
  await page.waitForSelector\('input[type=\\"email\\"]'\);
  await page.fill\('input[type=\\"email\\"]', 'teacher@apboost.test'\);
  await page.fill\('input[type=\\"password\\"]', 'Teacher123!'\);
  await page.click\('button[type=\\"submit\\"]'\);
  await sleep\(4000\);
  await page.goto\('http://localhost:5173/ap'\);
  await sleep\(2000\);

  // Click Macro
  const macroCard = page.locator\('h3'\).filter\({ hasText: /Macro/ }\);
  await macroCard.first\(\).click\(\);
  await page.waitForURL\(/\\/ap\\/test\\\\//, { timeout: 10000 }\);
  await sleep\(1500\);

  if \(await page.locator\('button:has-text\(\\"Resume Test\\"\)'\).count\(\) > 0\) {
    await page.click\('button:has-text\(\\"Resume Test\\"\)'\);
  } else {
    await page.click\('button:has-text\(\\"Begin Test\\"\)'\);
  }
  await sleep\(2000\);

  const inFRQ = await page.locator\('text=Choose how you'\).count\(\) > 0;
  if \(inFRQ\) {
    await page.locator\('button:has-text\(\\"Type Your Answers\\"\)'\).click\(\);
    await sleep\(1000\);
  }

  console.log\('Started macro test'\);

  // The answer buttons contain letter + choice text, so select by checking parent structure
  // The structure is: flex-1 flex items-start gap-3 p-3 button \(with letter badge + choice text\)
  const answerChoiceBtns = page.locator\('button[class*=\\"flex-1 flex items-start\\"]'\);
  const count = await answerChoiceBtns.count\(\);
  console.log\('Answer choice buttons:', count\);

  // Answer Q1-Q5 by selecting first choice each time
  for \(let q = 1; q <= 5; q++\) {
    const qText = await page.locator\('text=Question ' + q\).count\(\) > 0;
    console.log\('Q' + q + ' visible:', qText\);

    // Select first answer choice
    const choices = page.locator\('button[class*=\\"flex-1 flex items-start\\"]'\);
    const cCount = await choices.count\(\);
    if \(cCount > 0\) {
      await choices.first\(\).click\(\);
      await sleep\(200\);
    }

    // Flag Q3, Q4
    if \(q === 3 || q === 4\) {
      const flagBtn = page.locator\('button:has-text\(\\"Flag for Review\\"\)'\);
      if \(await flagBtn.count\(\) > 0\) {
        await flagBtn.first\(\).click\(\);
        await sleep\(200\);
        const flagged = await page.locator\('button:has-text\(\\"Flagged\\"\)'\).count\(\) > 0;
        console.log\('Q' + q + ' flagged:', flagged\);
      }
    }

    // Next
    if \(q < 5\) {
      const nxt = page.locator\('button:has-text\(\\"Next\\"\)'\).last\(\);
      if \(await nxt.count\(\) > 0 && await nxt.isEnabled\(\)\) {
        await nxt.click\(\);
        await sleep\(300\);
      }
    }
  }

  console.log\('Answered Q1-Q5'\);

  // Navigate to Q15 via navigator
  const centerNav = page.locator\('button'\).filter\({ hasText: /Question 5 of/ }\);
  if \(await centerNav.count\(\) > 0\) {
    await centerNav.first\(\).click\(\);
    await sleep\(600\);

    const navVisible = await page.locator\('text=Question Navigator'\).count\(\) > 0;
    console.log\('Navigator visible:', navVisible\);

    if \(navVisible\) {
      // Find Q15 button in navigator
      const navBtns = page.locator\('button'\);
      const allNavBtns = await navBtns.all\(\);
      for \(const btn of allNavBtns\) {
        const txt = await btn.textContent\(\).catch\(\(\) => ''\);
        if \(txt.trim\(\) === '15'\) {
          await btn.click\(\);
          await sleep\(600\);
          const q15vis = await page.locator\('text=Question 15'\).count\(\) > 0;
          console.log\('Q15 shown:', q15vis\);
          break;
        }
      }
    }
  } else {
    // Next through Q6-Q15
    for \(let i = 5; i < 15; i++\) {
      const nxt = page.locator\('button:has-text\(\\"Next\\"\)'\).last\(\);
      if \(await nxt.count\(\) > 0\) { await nxt.click\(\); await sleep\(200\); }
    }
  }

  // Answer Q15
  const q15Choices = page.locator\('button[class*=\\"flex-1 flex items-start\\"]'\);
  const q15Count = await q15Choices.count\(\);
  console.log\('Q15 choices:', q15Count\);
  if \(q15Count > 0\) {
    await q15Choices.first\(\).click\(\);
    await sleep\(300\);
    console.log\('Q15 answered'\);
  }

  await page.screenshot\({ path: 'C:/Users/dmchw/vocaboost/b4_q15.png' }\);

  // Check for Review button \(last question in section\)
  const revBtns = await page.locator\('button'\).allTextContents\(\).catch\(\(\) => []\);
  console.log\('Available buttons:', JSON.stringify\(revBtns.filter\(t => t.trim\(\)\)\)\);

  const reviewBtn = page.locator\('button:has-text\(\\"Review\\"\)'\);
  const reviewCount = await reviewBtn.count\(\);
  console.log\('Review button count:', reviewCount\);

  if \(reviewCount > 0\) {
    await reviewBtn.first\(\).click\(\);
    await sleep\(1000\);
    await page.screenshot\({ path: 'C:/Users/dmchw/vocaboost/b4_review.png' }\);

    const reviewH = await page.locator\('text=Review Your Answers'\).count\(\) > 0;
    console.log\('Review screen heading:', reviewH\);

    const answeredLi = await page.locator\('li'\).filter\({ hasText: 'Answered:' }\).first\(\).textContent\(\).catch\(\(\) => 'N/A'\);
    const unansweredLi = await page.locator\('li'\).filter\({ hasText: 'Unanswered:' }\).first\(\).textContent\(\).catch\(\(\) => 'N/A'\);
    const flaggedLi = await page.locator\('li'\).filter\({ hasText: 'Flagged:' }\).first\(\).textContent\(\).catch\(\(\) => 'N/A'\);
    console.log\('Answered:', answeredLi\);
    console.log\('Unanswered:', unansweredLi\);
    console.log\('Flagged:', flaggedLi\);

    const unanswWarn = await page.locator\('text=unanswered question'\).count\(\) > 0;
    console.log\('Unanswered warning visible:', unanswWarn\);

    const submitSection = await page.locator\('button:has-text\(\\"Submit Section\\"\)'\).count\(\) > 0;
    const submitTest = await page.locator\('button:has-text\(\\"Submit Test\\"\)'\).count\(\) > 0;
    console.log\('Submit Section button:', submitSection\);
    console.log\('Submit Test button \(should be false for section 1 of 2\):', submitTest\);

    if \(submitSection\) {
      await page.click\('button:has-text\(\\"Submit Section\\"\)'\);
      await sleep\(2500\);
      await page.screenshot\({ path: 'C:/Users/dmchw/vocaboost/b4_frq_choice.png' }\);
      console.log\('After Submit Section URL:', page.url\(\)\);

      const frqChoice = await page.locator\('text=Free Response Section'\).count\(\) > 0;
      const typeAnswers = await page.locator\('text=Type Your Answers'\).count\(\) > 0;
      const writeHand = await page.locator\('text=Write by Hand'\).count\(\) > 0;
      console.log\('FRQ choice screen:', frqChoice\);
      console.log\('Type Your Answers:', typeAnswers\);
      console.log\('Write by Hand:', writeHand\);

      // Check timer is still displayed
      const timerInChoice = await page.locator\('[class*=\\"mono\\"]'\).count\(\) > 0;
      console.log\('Timer in FRQ choice:', timerInChoice\);

      if \(typeAnswers\) {
        await page.locator\('button:has-text\(\\"Type Your Answers\\"\)'\).click\(\);
        await sleep\(1000\);
        await page.screenshot\({ path: 'C:/Users/dmchw/vocaboost/b4_frq_typed.png' }\);

        const frqTA = await page.locator\('textarea'\).count\(\) > 0;
        console.log\('FRQ textarea:', frqTA\);

        const secHeader = await page.locator\('header span'\).filter\({ hasText: 'Section' }\).textContent\(\).catch\(\(\) => 'N/A'\);
        console.log\('Section header in FRQ:', secHeader\);

        const lockIcon = await page.locator\('text=Locked'\).count\(\) > 0;
        console.log\('Lock indicator visible:', lockIcon\);

        // Type brief answers and submit
        let loop = 0;
        while \(loop < 20\) {
          const ta = page.locator\('textarea'\);
          if \(await ta.count\(\) > 0\) {
            const v = await ta.first\(\).inputValue\(\).catch\(\(\) => ''\);
            if \(!v\) { await ta.first\(\).fill\('Test FRQ answer.'\); await sleep\(100\); }
          }
          const revB = page.locator\('button:has-text\(\\"Review\\"\)'\);
          const nxtB = page.locator\('button:has-text\(\\"Next\\"\)'\).last\(\);
          if \(await revB.count\(\) > 0 && await revB.first\(\).isEnabled\(\)\) {
            await revB.first\(\).click\(\); await sleep\(800\); break;
          } else if \(await nxtB.count\(\) > 0 && await nxtB.isEnabled\(\)\) {
            await nxtB.click\(\); await sleep\(300\);
          } else { break; }
          loop++;
        }

        await page.screenshot\({ path: 'C:/Users/dmchw/vocaboost/b4_frq_review.png' }\);

        const submitTestFinal = page.locator\('button:has-text\(\\"Submit Test\\"\)'\);
        if \(await submitTestFinal.count\(\) > 0\) {
          console.log\('FRQ review - Submit Test button found'\);
          await submitTestFinal.first\(\).click\(\);
          await sleep\(8000\);
          console.log\('After final submit URL:', page.url\(\)\);

          if \(page.url\(\).includes\('/results/'\)\) {
            await page.screenshot\({ path: 'C:/Users/dmchw/vocaboost/b4_report.png' }\);
            const scoreRpt = await page.locator\('text=SCORE REPORT'\).count\(\) > 0;
            const mcqTbl = await page.locator\('table'\).count\(\) > 0;
            const backDash = await page.locator\('text=Back to Dashboard'\).count\(\) > 0;
            console.log\('SCORE REPORT:', scoreRpt\);
            console.log\('MCQ table:', mcqTbl\);
            console.log\('Back to Dashboard:', backDash\);
          }
        }
      }
    }
  }

  const errors = logs.filter\(l => l.type === 'error'\);
  console.log\('\\nErrors:', errors.length\);
  errors.forEach\(e => console.log\(' E:', e.text.substring\(0, 200\)\)\);

  await browser.close\(\);
  console.log\('Done'\);
}\)\(\).catch\(e => { console.error\('FATAL:', e.message\); process.exit\(1\); }\);
